interface I18nContextType {
  lang: Lang;
  setLang: (l: Lang) => void;
  t: (key: string, vars?: Record<string, string>) => string;
}

const I18nContext = createContext<I18nContextType>({
  lang: 'en',
  setLang: () => {},
  t: (key) => key,
});

export function I18nProvider({ children }: { children: ReactNode }) {
  // Always render 'en' on the server and on the first client paint to avoid
  // hydration mismatches when localStorage has a different value.
  // The effect below updates lang after mount.
  const [lang, setLangState] = useState<Lang>('en');
  useEffect(() => {
    const stored = (localStorage.getItem('vpn-lang') as Lang) ?? 'en';
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setLangState(stored);
  }, []);

  const setLang = useCallback((l: Lang) => {
    setLangState(l);
    if (typeof window !== 'undefined') localStorage.setItem('vpn-lang', l);
  }, []);

  const t = useCallback((key: string, vars?: Record<string, string>) => {
    let text = translations[key]?.[lang] ?? translations[key]?.en ?? key;
    if (vars) {
      for (const [k, v] of Object.entries(vars)) {
        text = text.replace(`{${k}}`, v);
      }
    }
    return text;
  }, [lang]);

  return (
    <I18nContext.Provider value={{ lang, setLang, t }}>
      {children}
    </I18nContext.Provider>
  );
}

export function useI18n() {
  return useContext(I18nContext);
}
